//! Spec-compliance audit: Section Properties (§17.6) + CompatSettings (MS-DOCX §2.3)
//!
//! These tests probe specific gaps in our section and compatibility settings parsing.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`,
//! function `make_section_compat_audit_fixtures()`.

use stemma::{BlockNode, CanonDoc, SectionProperties, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/section-compat-audit";

// -- helpers ----------------------------------------------------------------
/// Collect all paragraphs that have structured section properties.
fn section_paragraphs(doc: &CanonDoc) -> Vec<&SectionProperties> {
    let mut props = Vec::new();
    collect_section_props_tracked(&doc.blocks, &mut props);
    props
}

fn collect_section_props_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a SectionProperties>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_section_props_bare<'a>(blocks: &'a [BlockNode], out: &mut Vec<&'a SectionProperties>) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

// ==========================================================================
// SECTION PROPERTIES (ECMA-376 §17.6)
// ==========================================================================

// -- docGrid (§17.6.5) ----------------------------------------------------

/// ECMA-376 §17.6.5: docGrid defines the document grid (type, linePitch, charSpace).
///
/// The fixture has docGrid with type=linesAndChars, linePitch=312, charSpace=4096.
/// Our SectionProperties has no field for docGrid — this is a domain model gap.
///
/// SectionProperties docGrid fields.
#[test]
fn audit_section_doc_grid_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "doc-grid");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];
    assert_eq!(
        props.doc_grid_type,
        Some(stemma::domain::DocGridType::LinesAndChars),
        "docGrid type"
    );
    assert_eq!(props.doc_grid_line_pitch, Some(312), "docGrid linePitch");
    assert_eq!(props.doc_grid_char_space, Some(4096), "docGrid charSpace");
}

// -- rtlGutter (§17.6.15) -------------------------------------------------

/// ECMA-376 §17.6.15: rtlGutter moves the page gutter to the right side.
///
/// The fixture has <w:rtlGutter/> with gutter=720.
/// Our SectionProperties has no field for rtlGutter — gutter position is lost.
///
/// SectionProperties rtlGutter boolean.
#[test]
fn audit_section_rtl_gutter_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rtl-gutter");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];

    // Gutter value should be parsed (this works already)
    assert_eq!(props.gutter, Some(720), "gutter value should be 720");

    assert_eq!(props.rtl_gutter, Some(true), "rtlGutter should be true");
}

// -- textDirection (§17.6.19) ----------------------------------------------

/// ECMA-376 §17.6.19: textDirection specifies text flow direction in a section.
///
/// The fixture has textDirection=tbRl (vertical top-to-bottom, right-to-left).
/// Our SectionProperties has no field for textDirection.
///
/// SectionProperties textDirection field.
#[test]
fn audit_section_text_direction_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "text-direction");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];
    assert_eq!(
        props.text_direction,
        Some(stemma::domain::TextDirection::TbRl),
        "textDirection should be tbRl"
    );
}

// -- lnNumType distance (§17.6.8) -----------------------------------------

/// ECMA-376 §17.6.8: lnNumType has a distance attribute specifying the gap
/// between text margin and line numbers (in twips).
///
/// The fixture has lnNumType with distance=720 (half inch).
/// Our LineNumbering struct has countBy, start, restart but NOT distance.
///
/// LineNumbering distance field.
#[test]
fn audit_line_numbering_distance_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "line-num-distance");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];
    let ln = props
        .line_numbering
        .as_ref()
        .expect("should have line numbering");

    // These should work (already implemented)
    assert_eq!(ln.count_by, Some(1));
    assert_eq!(ln.start, Some(0));
    assert_eq!(ln.restart.as_deref(), Some("newPage"));

    assert_eq!(ln.distance, Some(720), "distance should be 720 twips");
}

// -- pgBorders space attribute (§17.6.7) -----------------------------------

/// ECMA-376 §17.6.7: Each page border edge has a space attribute specifying
/// the offset distance from the page/text margin.
///
/// The fixture has borders with space values: top=31, bottom=31, left=24, right=24.
/// Our Border struct has style, color, size but NOT space.
///
/// Border struct space field for page border offsets.
#[test]
fn audit_pg_border_space_attribute() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "pg-border-space");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];
    let borders = props
        .page_borders
        .as_ref()
        .expect("should have page borders");

    // Style and color should work
    let top = borders.top.as_ref().expect("should have top border");
    assert_eq!(top.style, stemma::domain::BorderStyle::Single);
    assert_eq!(top.color.as_deref(), Some("000000"));

    assert_eq!(top.space, Some(31), "top border space should be 31");
    let bottom = borders.bottom.as_ref().expect("should have bottom border");
    assert_eq!(bottom.space, Some(31), "bottom border space should be 31");
    let left = borders.left.as_ref().expect("should have left border");
    assert_eq!(left.space, Some(24), "left border space should be 24");
    let right = borders.right.as_ref().expect("should have right border");
    assert_eq!(right.space, Some(24), "right border space should be 24");
}

