// -- enableOpenTypeFeatures (§2.3.3) ---------------------------------------

/// MS-DOCX §2.3.3: enableOpenTypeFeatures controls whether OpenType features
/// like kerning, ligatures, contextual alternates are used.
///
/// The fixture has compatibilityMode=15 and enableOpenTypeFeatures=1.
/// Our CompatSettings does not have a field for enableOpenTypeFeatures.
///
/// CompatSettings enableOpenTypeFeatures field.
#[test]
fn audit_compat_enable_opentype_features() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "compat-enable-opentype");

    // compatibilityMode should work (already implemented)
    assert_eq!(
        doc.compat_settings.compatibility_mode,
        Some(15),
        "compatibilityMode should be 15"
    );

    assert_eq!(
        doc.compat_settings.enable_open_type_features,
        Some(true),
        "enableOpenTypeFeatures should be Some(true)"
    );
}

