// -- Combined compat settings (§2.3) --------------------------------------

/// MS-DOCX §2.3: All common compat settings should be parsed.
///
/// The fixture has 6 settings: compatibilityMode=15,
/// overrideTableStyleFontSizeAndJustification=1, doNotFlipMirrorIndents=0,
/// enableOpenTypeFeatures=1, differentiateMultirowTableHeaders=1,
/// allowTextAfterFloatingTableBreak=0.
///
/// We currently parse only 3 of 6 settings.
///
/// CompatSettings combined settings from MS-DOCX §2.3.
#[test]
fn audit_compat_combined_all_settings() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "compat-combined");

    // These 3 should work (already implemented)
    assert_eq!(
        doc.compat_settings.compatibility_mode,
        Some(15),
        "compatibilityMode should be 15"
    );
    assert_eq!(
        doc.compat_settings
            .override_table_style_font_size_and_justification,
        Some(true),
        "overrideTableStyleFontSizeAndJustification should be true"
    );
    assert_eq!(
        doc.compat_settings.do_not_flip_mirror_indents,
        Some(false),
        "doNotFlipMirrorIndents should be false (val=0)"
    );

    assert_eq!(
        doc.compat_settings.enable_open_type_features,
        Some(true),
        "enableOpenTypeFeatures should be Some(true)"
    );
    assert_eq!(
        doc.compat_settings.differentiate_multirow_table_headers,
        Some(true),
        "differentiateMultirowTableHeaders should be Some(true)"
    );
    assert_eq!(
        doc.compat_settings.allow_text_after_floating_table_break,
        Some(false),
        "allowTextAfterFloatingTableBreak should be Some(false)"
    );
}
